mapper.select:
select cw.*, s.name as student_name, c.course_name, c.course_code, tc.class_code from course_withdrawal cw left join student s on cw.student_id = s.username left join course c on cw.course_id = c.id left join student_course sc on cw.student_id = sc.student_id and cw.course_id = sc.course_id left join teaching_class tc on sc.teaching_class_id = tc.id
and cw.student_id = #{student_id} and cw.course_id = #{course_id} and cw.status = #{status}
order by cw.withdrawal_time desc
